  ?season wdt:P179 wd:Q7279101 ; wdt:P154 3 .
  ?contestant wdt:P1545 ?season ; wdt:P1137 "Guy's team" ; wdt:P529 ?order .
  ?contestant wdt:P69 ?birthName .
} ORDER BY ?order LIMIT 1 OFFSET 1

